import React from 'react';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Navigation, Pagination, Autoplay, EffectFade } from 'swiper/modules';

// Swiper Stilleri
import 'swiper/css';
import 'swiper/css/navigation';
import 'swiper/css/pagination';
import 'swiper/css/effect-fade';

const slidesData = [
  {
    id: 1,
    title: "Şehrin Kalbinde Yaşam",
    desc: "Modern mimariyle birleşen konforlu alanlar sizi bekliyor.",
    image: "https://images.unsplash.com/photo-1449824913935-59a10b8d2000?auto=format&fit=crop&w=1200&q=80",
    link: "#"
  },
  {
    id: 2,
    title: "Doğa ile İç İçe",
    desc: "Gürültüden uzak, huzurlu bir çalışma ortamı tasarladık.",
    image: "https://images.unsplash.com/photo-1441974231531-c6227db76b6e?auto=format&fit=crop&w=1200&q=80",
    link: "#"
  },
  {
    id: 3,
    title: "Minimalist Detaylar",
    desc: "Az çoktur felsefesiyle hazırlanan yeni koleksiyonumuz.",
    image: "https://images.unsplash.com/photo-1505691938895-1758d7eaa511?auto=format&fit=crop&w=1200&q=80",
    link: "#"
  }
];

const ResponsiveSlider = () => {
  return (
    <div className="w-full h-[500px] md:h-[600px] lg:h-[700px] relative">
      <Swiper
        modules={[Navigation, Pagination, Autoplay, EffectFade]}
        effect="fade"
        loop={true}
        autoplay={{ delay: 5000, disableOnInteraction: false }}
        navigation={true}
        pagination={{ clickable: true }}
        className="w-full h-full"
      >
        {slidesData.map((slide) => (
          <SwiperSlide key={slide.id} className="relative w-full h-full">
            {/* Arka Plan Resmi */}
            <div className="absolute inset-0 w-full h-full">
              <img 
                src={slide.image} 
                alt={slide.title} 
                className="w-full h-full object-cover"
              />
              {/* Modern Karartma Katmanı (Overlay) */}
              <div className="absolute inset-0 bg-black/40 bg-gradient-to-t from-black/70 to-transparent"></div>
            </div>

            {/* İçerik Katmanı */}
            <div className="relative h-full flex items-center justify-center sm:justify-start px-8 md:px-20 lg:px-32">
              <div className="max-w-2xl text-center sm:text-left text-white">
                <h2 className="text-3xl md:text-5xl lg:text-6xl font-extrabold mb-4 leading-tight tracking-tight animate-fade-in-up">
                  {slide.title}
                </h2>
                <p className="text-sm md:text-xl text-gray-200 mb-8 max-w-lg leading-relaxed">
                  {slide.desc}
                </p>
                <div className="flex flex-col sm:flex-row gap-4 justify-center sm:justify-start">
                  <a 
                    href={slide.link} 
                    className="px-8 py-3 bg-white text-black font-bold rounded-lg hover:bg-gray-200 transition-all duration-300 transform hover:scale-105"
                  >
                    İncele
                  </a>
                  <button className="px-8 py-3 border-2 border-white/50 backdrop-blur-sm text-white font-semibold rounded-lg hover:bg-white/20 transition-all">
                    Bize Ulaşın
                  </button>
                </div>
              </div>
            </div>
          </SwiperSlide>
        ))}
      </Swiper>

      {/* Swiper Custom Style Overrides */}
      <style>{`
        .swiper-button-next, .swiper-button-prev {
          width: 50px;
          height: 50px;
          background: rgba(255, 255, 255, 0.1);
          backdrop-filter: blur(10px);
          border-radius: 50%;
          color: white !important;
          transition: all 0.3s ease;
        }
        .swiper-button-next:after, .swiper-button-prev:after {
          font-size: 18px !important;
          font-weight: bold;
        }
        .swiper-button-next:hover, .swiper-button-prev:hover {
          background: rgba(255, 255, 255, 0.3);
          transform: scale(1.1);
        }
        .swiper-pagination-bullet {
          width: 12px;
          height: 12px;
          background: rgba(255, 255, 255, 0.5);
          opacity: 1;
        }
        .swiper-pagination-bullet-active {
          width: 30px;
          border-radius: 6px;
          background: white !important;
          transition: width 0.3s ease;
        }
        @media (max-width: 640px) {
          .swiper-button-next, .swiper-button-prev { display: none; }
        }
      `}</style>
    </div>
  );
};

export default ResponsiveSlider;
